function parseWgetDebugStderr(stderr: string): WgetMeta {
  const statusRe = /^HTTP response sent\.\s+Flags:\s+(\d{3})\s+/m;
  const contentTypeRe = /^  Content-Type:\s+(.+)$/m;
  const contentLengthRe = /^  Content-Length:\s+(\d+)$/m;
